import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"🌾 黃豆市場深度分析報告（完整版）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告_完整版.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告_完整版.md"}'),h={name:"Deep32Q知識庫/產業洞察/黃豆研究/黃豆市場深度分析報告_完整版.md"};function o(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="🌾-黃豆市場深度分析報告-完整版" tabindex="-1">🌾 黃豆市場深度分析報告（完整版） <a class="header-anchor" href="#🌾-黃豆市場深度分析報告-完整版" aria-label="Permalink to &quot;🌾 黃豆市場深度分析報告（完整版）&quot;">​</a></h1><p><strong>報告日期：</strong> 2026-04-27 14:50 <strong>研究範圍：</strong> 全球黃豆市場（美國、巴西、阿根廷、中國） <strong>資料來源：</strong> USDA、CBOT、TradingView、Trading Economics、本地搜尋引擎</p><hr><h2 id="一、市場概況與最新報價" tabindex="-1">一、市場概況與最新報價 <a class="header-anchor" href="#一、市場概況與最新報價" aria-label="Permalink to &quot;一、市場概況與最新報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>數值</th></tr></thead><tbody><tr><td>CBOT 黃豆期貨（ZSN6）</td><td><strong>1,166.06 美分/蒲式耳</strong></td></tr><tr><td>近期高點</td><td>1,200（2026/03/12，兩年新高）</td></tr><tr><td>近期低點</td><td>1,152（四週低點）</td></tr><tr><td>歷史最高</td><td>1,794.75（2012/09）</td></tr><tr><td>歷史最低</td><td>401.50</td></tr><tr><td>YTD 漲幅</td><td>+12.29%</td></tr></tbody></table><hr><h2 id="二、供需基本面-usda-數據" tabindex="-1">二、供需基本面（USDA 數據） <a class="header-anchor" href="#二、供需基本面-usda-數據" aria-label="Permalink to &quot;二、供需基本面（USDA 數據）&quot;">​</a></h2><h3 id="_2-1-美國供給需求表" tabindex="-1">2.1 美國供給需求表 <a class="header-anchor" href="#_2-1-美國供給需求表" aria-label="Permalink to &quot;2.1 美國供給需求表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>2024/25</th><th>2025/26</th><th>2026/27（預測）</th></tr></thead><tbody><tr><td>種植面積</td><td>—</td><td>—</td><td>增加（玉米轉種）</td></tr><tr><td>結庫存</td><td>—</td><td>350M bu</td><td>355M bu（持平）</td></tr><tr><td>壓榨量</td><td>—</td><td>—</td><td><strong>26.1 億蒲式耳（歷史新高）</strong></td></tr><tr><td>出口</td><td>—</td><td>—</td><td>15.4 億蒲式耳（下修，南美競爭）</td></tr></tbody></table><h3 id="_2-2-全球供應格局" tabindex="-1">2.2 全球供應格局 <a class="header-anchor" href="#_2-2-全球供應格局" aria-label="Permalink to &quot;2.2 全球供應格局&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>2026/27 產量</th><th>特徵</th></tr></thead><tbody><tr><td><strong>巴西</strong></td><td><strong>177.8M 噸（歷史新高）</strong></td><td>連續三年破紀錄，Abiove 上調</td></tr><tr><td><strong>美國</strong></td><td>增加（玉米轉種）</td><td>農民因獲利更高轉種</td></tr><tr><td><strong>阿根廷</strong></td><td>待更新</td><td>乾旱風險</td></tr></tbody></table><h3 id="_2-3-中國進口需求" tabindex="-1">2.3 中國進口需求 <a class="header-anchor" href="#_2-3-中國進口需求" aria-label="Permalink to &quot;2.3 中國進口需求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>進口量</th><th>YoY</th></tr></thead><tbody><tr><td>2024</td><td>~105M 噸</td><td>—</td></tr><tr><td>2025</td><td><strong>111.83-112M 噸</strong></td><td>+6.5%（歷史新高）</td></tr><tr><td>2026E</td><td>~115M 噸</td><td>+3-4%</td></tr></tbody></table><ul><li>中國從巴西+美國進口佔 <strong>92%</strong></li><li>豬群復甦，維持強勁豆粕需求</li><li>壓榨利潤偏弱但需求穩定</li></ul><hr><h2 id="三、技術分析" tabindex="-1">三、技術分析 <a class="header-anchor" href="#三、技術分析" aria-label="Permalink to &quot;三、技術分析&quot;">​</a></h2><h3 id="_3-1-k-線型態" tabindex="-1">3.1 K 線型態 <a class="header-anchor" href="#_3-1-k-線型態" aria-label="Permalink to &quot;3.1 K 線型態&quot;">​</a></h3><ul><li><strong>近期型態</strong>：1,100-1,250 區間震盪，形成<strong>對稱三角收斂</strong></li><li><strong>突破方向</strong>：待觀察，向上突破 1,200 則看 1,250-1,300；向下跌破 1,150 則看 1,100</li></ul><h3 id="_3-2-均線系統" tabindex="-1">3.2 均線系統 <a class="header-anchor" href="#_3-2-均線系統" aria-label="Permalink to &quot;3.2 均線系統&quot;">​</a></h3><table tabindex="0"><thead><tr><th>均線</th><th>位置</th><th>意義</th></tr></thead><tbody><tr><td>MA20</td><td>~1,170</td><td>短期支撐</td></tr><tr><td>MA50</td><td>~1,155</td><td>中期支撐</td></tr><tr><td>MA200</td><td>~1,100</td><td>長期支撐</td></tr></tbody></table><ul><li>短期均線交織 → 盤整格局</li><li>價格在 MA20 附近震盪</li></ul><h3 id="_3-3-技術指標" tabindex="-1">3.3 技術指標 <a class="header-anchor" href="#_3-3-技術指標" aria-label="Permalink to &quot;3.3 技術指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>訊號</th></tr></thead><tbody><tr><td>RSI(14)</td><td>~52</td><td>中性</td></tr><tr><td>MACD</td><td>零軸附近</td><td>方向未明</td></tr><tr><td>KD</td><td>50 附近</td><td>中性</td></tr></tbody></table><h3 id="_3-4-季節性分析" tabindex="-1">3.4 季節性分析 <a class="header-anchor" href="#_3-4-季節性分析" aria-label="Permalink to &quot;3.4 季節性分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>月份</th><th>歷史漲跌機率</th><th>說明</th></tr></thead><tbody><tr><td>4-5月</td><td>漲 55%</td><td>種植季不確定性</td></tr><tr><td>6-7月</td><td>漲 60%</td><td>天氣炒作高峰</td></tr><tr><td>8-9月</td><td>跌 55%</td><td>收割壓力</td></tr><tr><td>10-11月</td><td>跌 50%</td><td>收割完成</td></tr></tbody></table><p><strong>目前 4 月底，正值種植季窗口期，季節性偏多。</strong></p><hr><h2 id="四、政策與貿易戰" tabindex="-1">四、政策與貿易戰 <a class="header-anchor" href="#四、政策與貿易戰" aria-label="Permalink to &quot;四、政策與貿易戰&quot;">​</a></h2><h3 id="_4-1-美中貿易戰影響" tabindex="-1">4.1 美中貿易戰影響 <a class="header-anchor" href="#_4-1-美中貿易戰影響" aria-label="Permalink to &quot;4.1 美中貿易戰影響&quot;">​</a></h3><table tabindex="0"><thead><tr><th>措施</th><th>影響</th></tr></thead><tbody><tr><td>美國對中國關稅 145%</td><td>黃豆出口受阻</td></tr><tr><td>中國報復性關稅</td><td>需求轉向巴西</td></tr><tr><td>中國進口多元化</td><td>巴西佔比持續上升</td></tr></tbody></table><h3 id="_4-2-巴西競爭地位" tabindex="-1">4.2 巴西競爭地位 <a class="header-anchor" href="#_4-2-巴西競爭地位" aria-label="Permalink to &quot;4.2 巴西競爭地位&quot;">​</a></h3><ul><li><strong>2026 年收割 177.8M 噸</strong>（歷史新高）</li><li>已成為中國最大黃豆供應來源</li><li>連續三年破纪录，持續擠壓美國市場份額</li></ul><hr><h2 id="五、天氣與種植進度" tabindex="-1">五、天氣與種植進度 <a class="header-anchor" href="#五、天氣與種植進度" aria-label="Permalink to &quot;五、天氣與種植進度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>地區</th><th>狀態</th><th>風險</th></tr></thead><tbody><tr><td>美國中西部</td><td>種植季高峰</td><td>降雨偏多可能延遲</td></tr><tr><td>巴西</td><td>收割尾聲，創紀錄</td><td>二季玉米可能減少</td></tr><tr><td>阿根廷</td><td>乾旱風險</td><td>拉尼娜影響</td></tr></tbody></table><hr><h2 id="六、風險矩陣" tabindex="-1">六、風險矩陣 <a class="header-anchor" href="#六、風險矩陣" aria-label="Permalink to &quot;六、風險矩陣&quot;">​</a></h2><table tabindex="0"><thead><tr><th>風險</th><th>機率</th><th>影響</th></tr></thead><tbody><tr><td>巴西大豐收壓價</td><td>高</td><td>中</td></tr><tr><td>美國天氣異常</td><td>中</td><td>高</td></tr><tr><td>貿易戰再升級</td><td>中</td><td>高</td></tr><tr><td>中國需求放緩</td><td>低-中</td><td>高</td></tr><tr><td>阿根廷乾旱</td><td>中</td><td>中</td></tr></tbody></table><hr><h2 id="七、投資建議" tabindex="-1">七、投資建議 <a class="header-anchor" href="#七、投資建議" aria-label="Permalink to &quot;七、投資建議&quot;">​</a></h2><h3 id="短期-1-3-月" tabindex="-1">短期（1-3 月） <a class="header-anchor" href="#短期-1-3-月" aria-label="Permalink to &quot;短期（1-3 月）&quot;">​</a></h3><ul><li><strong>方向</strong>：中性偏多，震盪格局</li><li><strong>策略</strong>：1,150 以下逢低佈局，1,200 以上減碼</li></ul><h3 id="中期-3-6-月" tabindex="-1">中期（3-6 月） <a class="header-anchor" href="#中期-3-6-月" aria-label="Permalink to &quot;中期（3-6 月）&quot;">​</a></h3><ul><li><strong>關鍵</strong>：美國種植季天氣</li><li><strong>方向</strong>：若天氣正常，偏空（巴西豐收 + 美國擴種）</li></ul><h3 id="長期-6-12-月" tabindex="-1">長期（6-12 月） <a class="header-anchor" href="#長期-6-12-月" aria-label="Permalink to &quot;長期（6-12 月）&quot;">​</a></h3><ul><li><strong>結構</strong>：巴西持續擴產、中美貿易戰常態化</li><li><strong>方向</strong>：偏空，關注天氣黑天鵝</li></ul><hr><p><em>本報告由 Gale 整合 3 路 Dr.32 深挖資料 + 本地搜尋引擎資料編纂。</em><em>資料截至 2026-04-27。免責聲明：僅供研究參考，不構成投資建議。</em></p>',48)])])}const c=d(h,[["render",o]]);export{_ as __pageData,c as default};
